const matches = items[0].json.matches || [];
const sequence_name = items[0].json.name + "_sequence";

// 1. Process Files (Identify unique media files)
const fileMap = {}; 
let fileCounter = 1;

matches.forEach(m => {
  if (!fileMap[m.name]) {
    fileMap[m.name] = {
      id: `file-${fileCounter}`,
      name: m.name,
      uuid: generateUUID()
    };
    fileCounter++;
  }
});

// 2. Process Clips
let timelineCursorFrame = 0;
const clipData = [];
let clipIdCounter = 1;

for (const match of matches) {
  if (!match.words || match.words.length === 0) continue; 

  const fileInfo = fileMap[match.name];

  // --- PRECISION CUTTING (Word Level) ---
  const firstWord = match.words[0];
  const lastWord = match.words[match.words.length - 1];

  // Frame Calculation using User's Two-Step Integer Logic
  const startFrame = timeToFrameInteger(firstWord.start, TIMEBASE) -START_FRAME_BUFFER;
  const endFrame = timeToFrameInteger(lastWord.end, TIMEBASE)+ START_FRAME_BUFFER;
  const durationFrames = endFrame - startFrame;

  // *** NEW: PPRO Ticks Derived from the Calculated Integer Frames ***
  // This ensures perfect frame/tick alignment, resolving the float issue.
  const pproTicksIn = Math.round(startFrame * FRAME_TO_TICKS_RATIO);
  const pproTicksOut = Math.round(endFrame * FRAME_TO_TICKS_RATIO);

  // Generate unique IDs for the clip elements
  const vidClipId = `clipitem-${clipIdCounter++}`;
  const audClipId1 = `clipitem-${clipIdCounter++}`;
  const audClipId2 = `clipitem-${clipIdCounter++}`;

  clipData.push({
    fileId: fileInfo.id,
    filename: fileInfo.name,
    vidId: vidClipId,
    audId1: audClipId1,
    audId2: audClipId2,

    // Source Media In/Out
    inFrame: startFrame,
    outFrame: endFrame,
    pproTicksIn: pproTicksIn,
    pproTicksOut: pproTicksOut,

    // Sequence Timeline Placement (Continuous)
    tlStart: timelineCursorFrame,
    tlEnd: timelineCursorFrame + durationFrames,
    duration: durationFrames
  });

  // Increment Timeline Cursor
  timelineCursorFrame += durationFrames;
}

